using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private static readonly List<Shipment> _shipments = GenerateSeedData();

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(_shipments.ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(
            s => s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        var result = _shipments
            .Where(s => s.CustomerEmail.Equals(customerEmail, StringComparison.OrdinalIgnoreCase))
            .ToList();
        return Task.FromResult(result);
    }

    public Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
            shipment.Status = status;
        return Task.CompletedTask;
    }

    private static List<Shipment> GenerateSeedData() =>
    [
        new()
        {
            Id = 1, TrackingNumber = "TRK-10001", Origin = "New York, US",
