@page "/"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]

<PageTitle>ShipmentTracker - Home</PageTitle>

<h1>Shipment Tracker</h1>

<AuthorizeView Roles="Dispatcher">
    <Authorized>
        <p class="lead">Welcome, Dispatcher. <a href="/shipments">View all shipments</a> to manage logistics.</p>
    </Authorized>
</AuthorizeView>

<AuthorizeView>
    <Authorized>
        <p class="lead">Track your shipments below or visit <a href="/my-shipments">My Shipments</a>.</p>

        <div class="card mt-4" style="max-width: 500px;">
            <div class="card-body">
                <h5 class="card-title">Quick Track</h5>
                <div class="input-group">
                    <input type="text" class="form-control" placeholder="Enter tracking number (e.g. TRK-10001)"
                           @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
                    <button class="btn btn-primary" @onclick="Track">Track</button>
                </div>
                @if (!string.IsNullOrEmpty(errorMessage))
                {
                    <div class="alert alert-warning mt-2">@errorMessage</div>
                }
            </div>
        </div>
    </Authorized>
</AuthorizeView>

@code {
    private string trackingNumber = string.Empty;
    private string errorMessage = string.Empty;

    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private void Track()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
        {
            errorMessage = "Please enter a tracking number.";
            return;
        }
        errorMessage = string.Empty;
        Navigation.NavigateTo($"/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            Track();
    }
}

