@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>All Shipments</PageTitle>

<h1>Shipments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var s in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments => shipments!
        .Where(s => string.IsNullOrEmpty(filterText) ||
                    s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) ||
                    s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

@page "/track/{TrackingNumber}"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Shipment</h1>

<div class="mb-3" style="max-width: 500px;">
    <div class="input-group">
        <input type="text" class="form-control" placeholder="Tracking number"
               @bind="searchNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
        <button class="btn btn-primary" @onclick="Search">Search</button>
    </div>
</div>

@if (loading)
{
    <p><em>Searching...</em></p>
}
else if (shipment is not null)
{
    <div class="card mt-3" style="max-width: 600px;">
        <div class="card-header">
            <strong>@shipment.TrackingNumber</strong> — @shipment.Description
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-5">Status</dt>
                <dd class="col-sm-7"><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>

                <dt class="col-sm-5">Origin</dt>
                <dd class="col-sm-7">@shipment.Origin</dd>

                <dt class="col-sm-5">Destination</dt>
                <dd class="col-sm-7">@shipment.Destination</dd>

                <dt class="col-sm-5">Shipped Date</dt>
                <dd class="col-sm-7">@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>

                <dt class="col-sm-5">Estimated Delivery</dt>
                <dd class="col-sm-7">
                    <strong>@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</strong>
                    @if (shipment.Status != ShipmentStatus.Delivered)
                    {
                        var daysLeft = (shipment.EstimatedDelivery - DateTime.UtcNow).Days;
                        <span class="text-muted">(@(daysLeft > 0 ? $"in {daysLeft} days" : "arriving today or overdue"))</span>
                    }
                </dd>
            </dl>
        </div>
    </div>
}
else if (searched)
{
    <div class="alert alert-warning mt-3">No shipment found for tracking number <strong>@TrackingNumber</strong>.</div>
}

@code {
    [Parameter] public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? shipment;
    private string searchNumber = string.Empty;
    private bool loading;
    private bool searched;

    [Inject] private NavigationManager Navigation { get; set; } = default!;

    protected override async Task OnParametersSetAsync()
    {
        searchNumber = TrackingNumber;
        if (!string.IsNullOrWhiteSpace(TrackingNumber))
        {
            loading = true;
            searched = false;
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(TrackingNumber);
            loading = false;
            searched = true;
        }
    }

    private void Search()
    {
        if (!string.IsNullOrWhiteSpace(searchNumber))
            Navigation.NavigateTo($"/track/{Uri.EscapeDataString(searchNumber.Trim())}");
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            Search();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

@page "/my-shipments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>My Shipments</PageTitle>

<h1>My Shipments</h1>

@if (shipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <div class="alert alert-info">You have no shipments on record.</div>
}
else
{
    <div class="row mb-3">
        <div class="col-md-3">
            <select class="form-select" @bind="statusFilter">
                <option value="">All Statuses</option>
                @foreach (var s in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@s">@s</option>
                }
            </select>
        </div>
    </div>

    <div class="row">
        @foreach (var shipment in FilteredShipments)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">
                            <code>@shipment.TrackingNumber</code>
                            <span class="badge @GetStatusBadgeClass(shipment.Status) ms-2">@shipment.Status</span>
                        </h5>
                        <p class="card-text">@shipment.Description</p>
                        <ul class="list-unstyled">
                            <li><strong>From:</strong> @shipment.Origin</li>
                            <li><strong>To:</strong> @shipment.Destination</li>
                            <li><strong>Est. Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")
                                @if (shipment.Status != ShipmentStatus.Delivered)
                                {
                                    var daysLeft = (shipment.EstimatedDelivery - DateTime.UtcNow).Days;
                                    <span class="text-muted">(@(daysLeft > 0 ? $"{daysLeft} days left" : "arriving today or overdue"))</span>
                                }
                            </li>
                        </ul>
                        <a href="/track/@shipment.TrackingNumber" class="btn btn-sm btn-outline-primary">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Shipment>? shipments;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments => shipments!
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        var email = authState.User.Identity?.Name ?? string.Empty;
        shipments = await ShipmentService.GetShipmentsByCustomerAsync(email);
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

